import express2 from "express";

// src/modules/auth/auth.controller.ts
import httpStatus2 from "http-status";

// src/modules/auth/auth.service.ts
import bcrypt2 from "bcryptjs";
var loginUser = async (payload) => {
  const { email, password } = payload;
  const user = await prisma.user.findUnique({ where: { email } });
  if (!user) throw new Error("User not found");
  if (user.status === "BANNED") {
    throw new Error("Your account has been banned.");
  }
  const isPasswordMatched = await bcrypt2.compare(password, user.password);
  if (!isPasswordMatched) throw new Error("Password is incorrect");
  const jwtPayload = { id: user.id, email: user.email, role: user.role };
  const accessToken = jwtUtils.createToken(jwtPayload, config_default.jwt_access_secret, config_default.jwt_access_expires_in);
  const refreshToken3 = jwtUtils.createToken(jwtPayload, config_default.jwt_refresh_secret, config_default.jwt_refresh_expires_in);
  return { accessToken, refreshToken: refreshToken3 };
};
var refreshToken = async (token) => {
  const verifiedRefreshToken = jwtUtils.verifyToken(token, config_default.jwt_refresh_secret);
  if (!verifiedRefreshToken.success) throw new Error(verifiedRefreshToken.error);
  const { id } = verifiedRefreshToken.data;
  const user = await prisma.user.findUniqueOrThrow({ where: { id } });
  if (user.status === "BANNED") throw new Error("User is banned!");
  const jwtPayload = { id, name: user.name, email: user.email, role: user.role };
  const accessToken = jwtUtils.createToken(jwtPayload, config_default.jwt_access_secret, config_default.jwt_access_expires_in);
  return { accessToken };
};
var authService = { loginUser, refreshToken };

// src/modules/auth/auth.controller.ts
var loginUser2 = catchAsync(async (req, res) => {
  const result = await authService.loginUser(req.body);
  const { accessToken, refreshToken: refreshToken3 } = result;
  res.cookie("refreshToken", refreshToken3, {
    secure: config_default.env === "production",
    httpOnly: true,
    maxAge: 7 * 24 * 60 * 60 * 1e3
    // 7 days
  });
  sendResponse(res, {
    statusCode: httpStatus2.OK,
    success: true,
    message: "User logged in successfully",
    data: { accessToken }
  });
});
var refreshToken2 = catchAsync(async (req, res) => {
  const { refreshToken: refreshToken3 } = req.cookies;
  const result = await authService.refreshToken(refreshToken3);
  sendResponse(res, {
    statusCode: httpStatus2.OK,
    success: true,
    message: "Access token refreshed",
    data: result
  });
});
var authController = { loginUser: loginUser2, refreshToken: refreshToken2 };

// src/modules/auth/auth.routes.ts
var router2 = express2.Router();
router2.post("/login", authController.loginUser);
router2.post("/refresh-token", authController.refreshToken);
var authRoutes = router2;

