import SSLCommerzPayment from "sslcommerz-lts";
var initiateSSLPayment = async (paymentData) => {
  const sslcz = new SSLCommerzPayment(
    config_default.ssl.store_id,
    config_default.ssl.store_passwd,
    config_default.ssl.is_live
  );
  const data = {
    total_amount: paymentData.total_amount,
    currency: "BDT",
    tran_id: paymentData.tran_id,
    success_url: `${config_default.ssl.success_url}?tran_id=${paymentData.tran_id}`,
    fail_url: `${config_default.ssl.fail_url}?tran_id=${paymentData.tran_id}`,
    cancel_url: `${config_default.ssl.cancel_url}?tran_id=${paymentData.tran_id}`,
    ipn_url: config_default.ssl.success_url,
    shipping_method: "NO",
    product_name: "Home Service Booking",
    product_category: "Service",
    product_profile: "general",
    cus_name: paymentData.customerName,
    cus_email: paymentData.customerEmail,
    cus_add1: paymentData.customerAddress,
    cus_city: "Dhaka",
    cus_country: "Bangladesh",
    cus_phone: paymentData.customerPhone,
    ship_name: paymentData.customerName,
    ship_add1: paymentData.customerAddress,
    ship_city: "Dhaka",
    ship_country: "Bangladesh",
    ship_postcode: 1e3
  };
  const apiResponse = await sslcz.init(data);
  return apiResponse;
};

// src/modules/payment/payment.service.ts
var createPayment = async (customerId, payload) => {
  const { bookingId } = payload;
  const booking = await prisma.booking.findUnique({
    where: { id: bookingId },
    include: { customer: true }
  });
  if (!booking) throw new Error("Booking not found");
  if (booking.customerId !== customerId) {
    throw new Error("You are not authorized to pay for this booking");
  }
  if (booking.status !== BookingStatus.ACCEPTED) {
    throw new Error("Booking must be accepted by technician before payment");
  }
  const existingPayment = await prisma.payment.findUnique({ where: { bookingId } });
  if (existingPayment && existingPayment.status === PaymentStatus.COMPLETED) {
    throw new Error("This booking is already paid");
  }
  const tran_id = existingPayment?.transactionId ?? `TXN-${uuidv4()}`;
  const payment = existingPayment ? existingPayment : await prisma.payment.create({
    data: {
      bookingId,
      transactionId: tran_id,
      amount: booking.price,
      status: PaymentStatus.PENDING
    }
  });
  const sslResponse = await initiateSSLPayment({
    total_amount: booking.price,
    tran_id: payment.transactionId,
    customerName: booking.customer.name,
    customerEmail: booking.customer.email,
    customerPhone: "01700000000",
    // schema-তে phone ফিল্ড নেই, চাইলে পরে যোগ করো
    customerAddress: booking.address
  });
  return { paymentUrl: sslResponse.GatewayPageURL, transactionId: payment.transactionId };
};
var confirmPayment = async (tran_id) => {
  const payment = await prisma.payment.findUnique({
    where: { transactionId: tran_id },
    include: { booking: true }
  });
  if (!payment) throw new Error("Payment not found");
  const updatedPayment = await prisma.payment.update({
    where: { transactionId: tran_id },
    data: { status: PaymentStatus.COMPLETED, paidAt: /* @__PURE__ */ new Date() }
  });
  await prisma.booking.update({
    where: { id: payment.bookingId },
    data: { status: BookingStatus.PAID }
  });
  return updatedPayment;
};
var failPayment = async (tran_id) => {
  const payment = await prisma.payment.update({
    where: { transactionId: tran_id },
    data: { status: PaymentStatus.FAILED }
  });
  return payment;
};
var getUserPayments = async (customerId) => {
  const payments = await prisma.payment.findMany({
    where: { booking: { customerId } },
    include: { booking: { include: { service: true } } },
    orderBy: { createdAt: "desc" }
  });
  return payments;
};
var getPaymentById = async (id, customerId) => {
  const payment = await prisma.payment.findUnique({
    where: { id },
    include: { booking: { include: { service: true } } }
  });
  if (!payment) throw new Error("Payment not found");
  if (payment.booking.customerId !== customerId) {
    throw new Error("You are not authorized to view this payment");
  }
  return payment;
};
var paymentService = {
  createPayment,
  confirmPayment,
  failPayment,
  getUserPayments,
  getPaymentById
};

